+        let event = SseEvent::message("Hello, World!");
+        let bytes = event.to_bytes();
+        let output = String::from_utf8_lossy(&bytes);
+        assert!(output.contains("data: Hello, World!\n"));
+        assert!(output.ends_with("\n\n"));
+    }
